update tea_assessment_record
status = #{status}, teaching_score = #{teachingScore}, research_score = #{researchScore}, service_score = #{serviceScore}, total_score = #{totalScore}, grade = #{grade}, self_evaluation = #{selfEvaluation}, dept_evaluation = #{deptEvaluation}, submit_time = #{submitTime}, update_by = #{updateBy}, update_time = sysdate()
where record_id = #{recordId}

mapper.select:
select COALESCE(AVG(r.total_score), 0) as avgScore, COALESCE(AVG(r.teaching_score), 0) as avgTeaching, COALESCE(AVG(r.research_score), 0) as avgResearch, COALESCE(AVG(r.service_score), 0) as avgService, COUNT(*) as totalCount, SUM(CASE WHEN r.grade = '优秀' THEN 1 ELSE 0 END) as excellentCount, SUM(CASE WHEN r.grade = '合格' THEN 1 ELSE 0 END) as passCount, SUM(CASE WHEN r.grade = '基本合格' THEN 1 ELSE 0 END) as basicCount, SUM(CASE WHEN r.grade = '不合格' THEN 1 ELSE 0 END) as failCount, d.dept_name as deptName from tea_assessment_record r left join tea_teacher t on t.teacher_id = r.teacher_id left join sys_dept d on d.dept_id = t.dept_id
AND r.plan_id = #{planId}
group by d.dept_id, d.dept_name
